import React, { useState, useEffect, useContext, useMemo } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import Footer from "./Footer";
import { DataContext } from "../DataContext/DataContext";
import { useDispatch, useSelector } from "react-redux";
import { createSelector } from "reselect";
import { getAllProducts } from "../features/products/productSlice";
import HomeAds from "./HomeAds";
import { AiFillHeart, AiOutlineHeart } from "react-icons/ai";
import { addToWishlist } from "../redux/actions/wishListActon";
import axios from "axios";
import { base_url } from "../utils/axiosConfig";
import HealthAdviceCard from "./HealthAdviceCard";
import ProductCard from "./ProductCard";

// Helper hook for query params
function useQuery() {
  return new URLSearchParams(useLocation().search);
}

const selectWishlist = createSelector(
  (state) => state?.auth?.wishlist?.wishlist,
  (wishlist) => wishlist || [],
);

function Search() {
  const navigate = useNavigate();
  const { data, loading, error } = useContext(DataContext);
  const location = useLocation();
  const dispatch = useDispatch();
  const queryParams = useQuery();

  const [minPrice, setMinPrice] = useState(0);
  const [maxPrice, setMaxPrice] = useState(0);
  const [currentPage, setCurrentPage] = useState(1);
  const [sortOrder, setSortOrder] = useState("latest");
  const [viewMode, setViewMode] = useState("grid");
  const [advice, setAdvice] = useState(null);
  const [showAdviceModal, setShowAdviceModal] = useState(false);

  const query = queryParams.get("query") || "";
  const productsPerPage = 12;

  const addedToWish = useSelector(selectWishlist);

  useEffect(() => {
    dispatch(getAllProducts());
  }, [dispatch]);

  // Fetch Health Advice when query changes
  useEffect(() => {
    if (query && query.trim().length > 1) {
      axios.get(`${base_url}health-advice/recommendations?query=${encodeURIComponent(query)}`)
        .then(res => {
          if (Array.isArray(res.data) && res.data.length === 0) {
            setAdvice(null);
          } else {
            setAdvice(res.data);
          }
        })
        .catch(err => {
          console.error("Error fetching health advice", err);
          setAdvice(null);
        });
    } else {
      setAdvice(null);
    }
    setShowAdviceModal(false); // Reset modal on query change
  }, [query]);

  const filteredProducts = useMemo(() => {
    if (!data) return [];
    let result = [...data];

    if (query) {
      const lcQuery = query.toLowerCase();
      result = result.filter(
        (p) =>
          p.title?.toLowerCase().includes(lcQuery) ||
          p.category?.toLowerCase().includes(lcQuery) ||
          p.subcategory?.toLowerCase().includes(lcQuery) ||
          p.description?.toLowerCase().includes(lcQuery) ||
          p.brand?.toLowerCase().includes(lcQuery)
      );
    }

    if (minPrice > 0 || maxPrice > 0) {
      result = result.filter((p) => {
        const pPrice = parseInt(p.price) || 0;
        const matchMin = minPrice === 0 || pPrice >= minPrice;
        const matchMax = maxPrice === 0 || pPrice <= maxPrice;
        return matchMin && matchMax;
      });
    }

    if (sortOrder === "latest") {
      result.sort((a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0));
    } else if (sortOrder === "priceLow") {
      result.sort((a, b) => (parseInt(a.price) || 0) - (parseInt(b.price) || 0));
    } else if (sortOrder === "priceHigh") {
      result.sort((a, b) => (parseInt(b.price) || 0) - (parseInt(a.price) || 0));
    }

    return result;
  }, [data, query, minPrice, maxPrice, sortOrder]);

  const totalPages = Math.ceil(filteredProducts.length / productsPerPage);
  const currentProducts = filteredProducts.slice(
    (currentPage - 1) * productsPerPage,
    currentPage * productsPerPage,
  );

  const handleWishlist = (pid) => dispatch(addToWishlist(pid, navigate, 1));

  const getProductImage = (p, index = 0) => {
    try {
        if (p.images && Array.isArray(p.images) && p.images[index] && p.images[index].secure_url) {
          return p.images[index].secure_url;
        }
        if (p.colors && Array.isArray(p.colors) && p.colors[0] && p.colors[0].images && Array.isArray(p.colors[0].images) && p.colors[0].images[index] && p.colors[0].images[index].secure_url) {
          return p.colors[0].images[index].secure_url;
        }
        if (index > 0) return getProductImage(p, 0);
    } catch (e) {
        console.error("Image access error", e);
    }
    return "https://res.cloudinary.com/dpkv77m87/image/upload/v1711200000/fallback_product_image.png";
  };

  if (loading && !data) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
        <div className="w-12 h-12 border-4 border-teal-100 border-t-teal-600 rounded-full animate-spin"></div>
        <p className="text-teal-900 font-bold tracking-tight">Accessing clinical catalog...</p>
      </div>
    );
  }

  return (
    <div className="bg-[#f8fafc] min-h-screen pb-20">
      <main className="max-w-[1440px] mx-auto">
        <HomeAds category="Search Results" />

        <section className="px-4 lg:px-10 py-10 md:py-16">
          {/* Clinical Insights Banner — Trigger for Modal */}
          {advice && Array.isArray(advice) && advice.length > 0 && (
            <div 
              onClick={() => setShowAdviceModal(true)}
              className="mb-12 bg-white rounded-[32px] p-6 border-2 border-teal-500/10 cursor-pointer transition-all duration-300 hover:shadow-xl hover:shadow-teal-500/5 hover:-translate-y-1 group relative overflow-hidden"
            >
              <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity">
                <svg xmlns="http://www.w3.org/2000/svg" width="120" height="120" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v10"/><path d="M18.4 4.6 12 11"/><path d="m5.6 4.6 6.4 6.4"/><path d="M2 12h10"/><path d="M12 12v10"/><path d="m18.4 19.4-6.4-6.4"/><path d="m5.6 19.4 6.4-6.4"/><path d="M22 12h-10"/></svg>
              </div>
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 relative z-10">
                <div className="flex items-center gap-5">
                  <div className="w-14 h-14 rounded-2xl bg-teal-600 flex items-center justify-center text-white shadow-lg shadow-teal-600/30">
                    <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v10"/><path d="M2 12h10"/></svg>
                  </div>
                  <div>
                    <h3 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight italic uppercase">Clinical Insights Found</h3>
                    <p className="text-slate-500 font-medium text-sm">Our pharmacists have found {advice.length} health guides relevant to your search</p>
                  </div>
                </div>
                <button 
                  className="px-6 py-3.5 bg-teal-600 text-white font-black rounded-2xl hover:bg-teal-700 transition-all shadow-xl shadow-teal-500/20 active:scale-95 uppercase tracking-widest text-[11px] flex items-center gap-2 self-start md:self-center"
                >
                  View Suggestions
                  <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m9 18 6-6-6-6"/></svg>
                </button>
              </div>
            </div>
          )}

          {/* Search Header Area */}
          <div className="bg-white rounded-3xl p-6 md:p-8 shadow-sm border border-slate-100 mb-10">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
              <div className="space-y-1">
                <div className="flex items-center gap-3 text-sm text-slate-500 font-semibold uppercase tracking-wider">
                  <span className="w-2 h-2 bg-teal-500 rounded-full"></span>
                  Results for
                </div>
                <h2 className="text-2xl md:text-3xl font-black text-slate-900 tracking-tighter italic uppercase">
                   "{query}"
                </h2>
                <p className="text-slate-400 font-medium text-sm">
                  Found {filteredProducts.length} premium products in our inventory
                </p>
              </div>

              <div className="flex flex-wrap items-center gap-4">
                <div className="flex items-center gap-3 bg-slate-50 p-1.5 rounded-2xl border border-slate-100">
                   <button
                    onClick={() => setViewMode("grid")}
                    className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all duration-200 ${viewMode === "grid" ? "bg-white text-teal-600 shadow-md ring-1 ring-slate-200/50" : "text-slate-400 hover:text-slate-600"}`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect width="7" height="7" x="3" y="3" rx="1"/><rect width="7" height="7" x="14" y="3" rx="1"/><rect width="7" height="7" x="14" y="14" rx="1"/><rect width="7" height="7" x="3" y="14" rx="1"/></svg>
                  </button>
                  <button
                    onClick={() => setViewMode("list")}
                    className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all duration-200 ${viewMode === "list" ? "bg-white text-teal-600 shadow-md ring-1 ring-slate-200/50" : "text-slate-400 hover:text-slate-600"}`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="8" y1="6" x2="21" y2="6"/><line x1="8" y1="12" x2="21" y2="12"/><line x1="8" y1="18" x2="21" y2="18"/><line x1="3" y1="6" x2="3.01" y2="6"/><line x1="3" y1="12" x2="3.01" y2="12"/><line x1="3" y1="18" x2="3.01" y2="18"/></svg>
                  </button>
                </div>

                <div className="relative group">
                   <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none group-focus-within:text-teal-500 transition-colors">
                     <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
                   </span>
                   <select
                    className="appearance-none bg-white border border-slate-200 text-slate-700 text-sm font-bold rounded-2xl focus:ring-4 focus:ring-teal-500/10 focus:border-teal-500 block w-full pl-10 pr-10 py-3 cursor-pointer transition-all hover:border-slate-300"
                    value={sortOrder}
                    onChange={(e) => setSortOrder(e.target.value)}
                  >
                    <option value="latest">Sort: Latest</option>
                    <option value="priceLow">Sort: Price Low</option>
                    <option value="priceHigh">Sort: Price High</option>
                  </select>
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m6 9 6 6 6-6"/></svg>
                  </span>
                </div>
              </div>
            </div>
          </div>

          {/* Product Grid/List Area */}
          <div className="mt-8">
            {filteredProducts.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-24 px-6 text-center bg-white rounded-[40px] border border-slate-100 shadow-sm">
                <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mb-6 text-slate-200 scale-150">
                   <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                </div>
                <h3 className="text-2xl font-black text-slate-900 tracking-tight mb-2 uppercase">No matches found</h3>
                <p className="text-slate-400 font-medium max-w-sm mx-auto mb-8">
                  We couldn't find any products matching <span className="text-teal-600 font-bold">"{query}"</span>. Try adjusting your search term or exploring categories.
                </p>
                <Link to="/shop" className="px-8 py-4 bg-teal-600 text-white font-black rounded-2xl hover:bg-teal-700 transition-all shadow-xl shadow-teal-600/20 active:scale-95 uppercase tracking-widest text-xs">
                  Browse Full Catalog
                </Link>
              </div>
            ) : viewMode === "grid" ? (
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 lg:gap-6">
                {currentProducts.map((product) => (
                  <ProductCard key={product._id} product={product} />
                ))}
              </div>
            ) : (
              <div className="space-y-6">
                {currentProducts.map((product) => (
                  <div className="group flex flex-col md:flex-row bg-white rounded-3xl border border-slate-100 p-4 transition-all duration-500 hover:shadow-xl hover:border-teal-100" key={product._id}>
                     <div className="w-full md:w-48 h-48 rounded-2xl overflow-hidden bg-slate-50 shrink-0">
                        <Link to={`/productdetails/${product._id}`} className="block w-full h-full">
                          <img
                            className="w-full h-full object-contain transition-transform duration-700 group-hover:scale-110"
                            src={getProductImage(product, 0)}
                            alt={product.title}
                          />
                        </Link>
                     </div>
                     <div className="flex-1 p-4 md:p-6 flex flex-col justify-between">
                        <div className="space-y-2">
                           <span className="text-[10px] font-black text-teal-600 uppercase tracking-widest block opacity-70">
                            {product.category}
                          </span>
                          <h3 className="text-xl font-bold text-slate-900 leading-tight group-hover:text-teal-600 transition-colors">
                            <Link to={`/productdetails/${product._id}`}>{product.title}</Link>
                          </h3>
                          <p className="text-slate-400 font-medium text-sm line-clamp-2 mt-2">
                            {product.description || "Premium quality from Pulse Addis. Verified clinical product."}
                          </p>
                        </div>
                        <div className="flex flex-wrap items-center justify-between gap-4 mt-6">
                           <div className="flex items-center gap-6">
                              <span className="text-2xl font-black text-slate-900">{product.price?.toLocaleString()} <span className="text-xs text-slate-400">ETB</span></span>
                              <span className={`px-3 py-1 text-[10px] font-black uppercase tracking-widest rounded-lg ${product.quantity > 0 ? "bg-teal-500 text-white shadow-lg shadow-teal-500/20" : "bg-red-500 text-white"}`}>
                                {product.quantity > 0 ? "In Stock" : "Out of Stock"}
                              </span>
                           </div>
                           <div className="flex gap-2">
                              <button
                                onClick={() => handleWishlist(product._id)}
                                className="w-12 h-12 bg-slate-50 border border-slate-100 rounded-2xl flex items-center justify-center text-slate-400 hover:text-red-500 transition-all"
                              >
                                {addedToWish.some((w) => w._id === product._id) ? (
                                  <AiFillHeart color="#ef4444" size={24} />
                                ) : (
                                  <AiOutlineHeart size={24} />
                                )}
                              </button>
                              <Link to={`/productdetails/${product._id}`} className="px-6 py-3 bg-teal-600 text-white font-black text-xs uppercase tracking-widest rounded-2xl hover:bg-teal-700 transition-all shadow-lg active:scale-95">
                                View Product Details
                              </Link>
                           </div>
                        </div>
                     </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="mt-16 flex justify-center">
              <nav className="inline-flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-100">
                <button
                  disabled={currentPage === 1}
                  onClick={() => {
                    setCurrentPage((p) => p - 1);
                    window.scrollTo({ top: 0, behavior: 'smooth' });
                  }}
                  className="w-10 h-10 flex items-center justify-center rounded-xl text-slate-400 hover:text-teal-600 disabled:opacity-30 disabled:pointer-events-none transition-colors"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
                </button>
                
                <div className="flex gap-1 px-2 border-x border-slate-100">
                  {Array.from({ length: totalPages }).map((_, i) => (
                    <button
                      key={i}
                      onClick={() => {
                        setCurrentPage(i + 1);
                        window.scrollTo({ top: 0, behavior: 'smooth' });
                      }}
                      className={`w-10 h-10 flex items-center justify-center rounded-xl font-black text-xs transition-all ${currentPage === i + 1 ? "bg-teal-600 text-white shadow-lg shadow-teal-600/30 ring-2 ring-teal-600/20" : "text-slate-400 hover:bg-slate-50 hover:text-slate-900"}`}
                    >
                      {i + 1}
                    </button>
                  ))}
                </div>

                <button
                  disabled={currentPage === totalPages}
                  onClick={() => {
                    setCurrentPage((p) => p + 1);
                    window.scrollTo({ top: 0, behavior: 'smooth' });
                  }}
                  className="w-10 h-10 flex items-center justify-center rounded-xl text-slate-400 hover:text-teal-600 disabled:opacity-30 disabled:pointer-events-none transition-colors"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m9 18 6-6-6-6"/></svg>
                </button>
              </nav>
            </div>
          )}
        </section>
        <Footer />
      </main>

      {/* ── Healthcare Suggestions Modal ── */}
      {showAdviceModal && advice && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-4 md:p-10 animate-in fade-in duration-300">
          {/* Backdrop */}
          <div 
            onClick={() => setShowAdviceModal(false)}
            className="absolute inset-0 bg-slate-950/60 backdrop-blur-md"
          ></div>

          {/* Modal Container */}
          <div className="relative w-full max-w-5xl max-h-[90vh] bg-[#f8fafc] rounded-[40px] shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 slide-in-from-bottom-10 duration-500">
            {/* Modal Header */}
            <div className="px-8 py-6 bg-white border-b border-slate-100 flex items-center justify-between shrink-0">
              <div className="flex items-center gap-4">
                <div className="w-10 h-10 rounded-xl bg-teal-500 flex items-center justify-center text-white shadow-lg shadow-teal-500/20">
                   <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v10"/><path d="M2 12h10"/></svg>
                </div>
                <div>
                  <h2 className="text-xl font-black text-slate-900 tracking-tight flex items-center gap-2">
                    Clinical Insights <span className="text-[10px] bg-teal-100 text-teal-700 px-2 py-0.5 rounded-full uppercase tracking-widest">{advice.length} Found</span>
                  </h2>
                  <p className="text-slate-400 text-xs font-medium italic">Verified Pharmacist Guidance</p>
                </div>
              </div>
              <button 
                onClick={() => setShowAdviceModal(false)}
                className="w-12 h-12 flex items-center justify-center rounded-2xl bg-slate-50 text-slate-400 hover:bg-rose-50 hover:text-rose-500 transition-all active:scale-90"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18M6 6l12 12"/></svg>
              </button>
            </div>

            {/* Modal Content - Scrollable Grid */}
            <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {advice.map((item, idx) => (
                  <div key={item._id || idx} className="h-full">
                    <HealthAdviceCard advice={item} />
                  </div>
                ))}
              </div>
            </div>

            {/* Modal Footer */}
            <div className="px-8 py-5 bg-slate-50 border-t border-slate-100 flex items-center justify-between shrink-0">
               <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">© Pulse Addis Healthcare Excellence</p>
               <button 
                 onClick={() => setShowAdviceModal(false)}
                 className="px-6 py-2.5 bg-slate-900 text-white font-black rounded-xl text-[11px] uppercase tracking-widest hover:bg-teal-600 transition-colors"
                >
                 Acknowledge
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Search;
