import React from "react";
import { Link } from "react-router-dom";

const HealthAdviceCard = ({ advice, onTagClick }) => {
  if (!advice) return null;

  const truncate = (str, n) => {
    if (!str) return "";
    return str.length <= n ? str : str.slice(0, n).trim() + "…";
  };

  // If advice is an array, take the first one (occurs in Search result recommendations)
  const actualAdvice = Array.isArray(advice) ? advice[0] : advice;
  if (!actualAdvice) return null;

  const heroImg = actualAdvice.image?.secure_url || actualAdvice.image?.url || null;

  return (
    <>
      <style>{CARD_CSS}</style>
      <Link to={`/health-advice/${actualAdvice._id}`} className="hac-card">
        {/* Image */}
        <div className="hac-img-wrap">
          {heroImg ? (
            <img src={heroImg} alt={advice.conditionName} className="hac-img" />
          ) : (
            <div className="hac-img-placeholder">
              <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" strokeWidth="1.5"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>
            </div>
          )}
          <span className="hac-type-chip">Clinical Guide</span>
        </div>

        {/* Content */}
        <div className="hac-body">
          <div className="hac-meta-row">
            <span className="hac-verified-badge">
              <span className="hac-verified-dot" />
              Verified
            </span>
            {actualAdvice.createdAt && (
              <span className="hac-date">
                {new Date(actualAdvice.createdAt).toLocaleDateString("en-US", {
                  month: "short",
                  day: "numeric",
                })}
              </span>
            )}
          </div>

          <h3 className="hac-title">{actualAdvice.conditionName || "Untitled Guide"}</h3>

          <p className="hac-snippet">{truncate(actualAdvice.healthAdvice, 90)}</p>

          {actualAdvice.keySymptoms?.length > 0 && (
            <div className="hac-tags">
              {actualAdvice.keySymptoms.slice(0, 3).map((s, i) => (
                <span
                  key={i}
                  className="hac-tag"
                  onClick={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    if (onTagClick) onTagClick(s);
                  }}
                  title={`Filter by: ${s}`}
                >
                  {s}
                </span>
              ))}
              {actualAdvice.keySymptoms.length > 3 && (
                <span className="hac-tag-more">+{actualAdvice.keySymptoms.length - 3}</span>
              )}
            </div>
          )}

          <div className="hac-footer">
            <span className="hac-read-link">
              Read Guide
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="m9 18 6-6-6-6"/></svg>
            </span>
          </div>
        </div>
      </Link>
    </>
  );
};

const CARD_CSS = `
  .hac-card {
    display: flex;
    flex-direction: column;
    background: #fff;
    border: 1px solid #f1f5f9;
    border-radius: 20px;
    overflow: hidden;
    text-decoration: none;
    height: 100%;
    transition: border-color 0.2s, box-shadow 0.2s, transform 0.25s cubic-bezier(.34,1.56,.64,1);
    box-shadow: 0 2px 12px rgba(0,0,0,0.03);
  }
  .hac-card:hover {
    border-color: #14b8a6;
    box-shadow: 0 12px 36px rgba(13,148,136,0.1);
    transform: translateY(-4px);
  }

  .hac-img-wrap {
    width: 100%;
    aspect-ratio: 16/9;
    position: relative;
    overflow: hidden;
    background: #f8fafc;
  }
  .hac-img {
    width: 100%; height: 100%;
    object-fit: cover;
    transition: transform 0.5s ease;
  }
  .hac-card:hover .hac-img { transform: scale(1.05); }

  .hac-img-placeholder {
    width: 100%; height: 100%;
    display: flex; align-items: center; justify-content: center;
    background: linear-gradient(135deg, #f0fdf4 0%, #ccfbf1 100%);
  }

  .hac-type-chip {
    position: absolute;
    top: 12px; right: 12px;
    background: rgba(255,255,255,0.9);
    backdrop-filter: blur(8px);
    border-radius: 8px;
    padding: 4px 10px;
    font-size: 10px;
    font-weight: 800;
    color: #0f172a;
    text-transform: uppercase;
    letter-spacing: 0.08em;
  }

  .hac-body {
    padding: 18px;
    display: flex;
    flex-direction: column;
    flex: 1;
  }

  .hac-meta-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 12px;
  }
  .hac-verified-badge {
    display: flex; align-items: center; gap: 6px;
    font-size: 11px; font-weight: 800;
    color: #0d9488;
    text-transform: uppercase; letter-spacing: 0.08em;
  }
  .hac-verified-dot {
    width: 6px; height: 6px;
    background: #14b8a6; border-radius: 50%;
    box-shadow: 0 0 8px rgba(20,184,166,0.5);
  }
  .hac-date { font-size: 12px; font-weight: 700; color: #64748b; }

  .hac-title {
    font-family: 'Plus Jakarta Sans', sans-serif;
    font-size: 18px;
    font-weight: 800;
    color: #0f172a;
    letter-spacing: -0.02em;
    line-height: 1.3;
    margin-bottom: 10px;
  }

  .hac-snippet {
    font-size: 13px;
    color: #64748b;
    line-height: 1.6;
    margin-bottom: 16px;
    font-weight: 400;
  }

  .hac-tags {
    display: flex; flex-wrap: wrap; gap: 6px;
    margin-bottom: 16px;
  }
  .hac-tag {
    background: #f1f5f9;
    color: #475569;
    font-size: 11px; font-weight: 600;
    padding: 4px 10px; border-radius: 6px;
    text-transform: capitalize;
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
  }
  .hac-tag:hover { background: #ccfbf1; color: #0d9488; }
  .hac-tag-more {
    background: #f1f5f9;
    color: #94a3b8;
    font-size: 11px; font-weight: 700;
    padding: 4px 8px; border-radius: 6px;
  }

  .hac-footer {
    margin-top: auto;
    padding-top: 14px;
    border-top: 1px solid #f8fafc;
    display: flex; align-items: center;
  }
  .hac-read-link {
    display: flex; align-items: center; gap: 4px;
    font-size: 12px; font-weight: 700;
    color: #14b8a6; text-transform: uppercase; letter-spacing: 0.06em;
    transition: gap 0.2s;
  }
  .hac-card:hover .hac-read-link { gap: 8px; }
`;

export default HealthAdviceCard;
